import * as lpUtils from './utils.js';

/**
 * Filter students
 */
const filter = (e, target) => {
	lpUtils.lpSetLoadingEl(target, 1);
	const gradebookSearchForm = target.closest('.lp-gradebook-filter');
	if ( ! gradebookSearchForm ) {
		return;
	}

	let lpTarget = document.querySelector('.lp-target');
	const dataSend = window.lpAJAXG.getDataSetCurrent(lpTarget);
	dataSend.args.paged = 1;
	const dataForm = lpUtils.getDataOfForm(gradebookSearchForm);
	const keys = lpUtils.getFieldKeysOfForm(gradebookSearchForm);
	keys.forEach((key) => {
		if (!dataForm.hasOwnProperty(key)) {
			delete dataSend.args[key];
		} else if (dataForm[key][0] === '') {
			delete dataForm[key];
			delete dataSend.args[key];
		}
	});

	dataSend.args = { ...dataSend.args, ...dataForm };
	window.lpAJAXG.setDataSetCurrent(lpTarget, dataSend);

	const lpTargetY =
		lpTarget.getBoundingClientRect().top + window.scrollY - 100;
	window.scrollTo({ top: lpTargetY });

	window.lpAJAXG.showHideLoading(lpTarget, 1);

	const callBack = {
		success: (response) => {
			const { status, message, data } = response;
			lpTarget.innerHTML = data.content || '';
		},
		error: (error) => {
			console.log(error);
		},
		completed: () => {
			window.lpAJAXG.showHideLoading(lpTarget, 0);
			lpUtils.lpSetLoadingEl(target, 0);
		},
	};

	window.lpAJAXG.fetchAJAX(dataSend, callBack);
};

document.addEventListener('click', (e) => {
	let target = e.target;
	if (target.classList.contains('gradebook-search-button')) {
		filter(e, target);
	} else if (target.classList.contains('gradebook-reset-button')) {
		const gradebookSearchForm = target.closest('.lp-gradebook-filter');
		gradebookSearchForm.reset();
		filter(e, target);
	}
});
document.addEventListener('reset', (e) => {
	if (e.target.classList.contains('gradebook-search-user')) {
		e.target
			.querySelectorAll('.tomselected')
			.forEach((tomselectedElement) => {
				tomselectedElement.tomselect.clear();
			});
	}
});
